INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('real-estate-moex-01812', 'real-estate', 'real-estate-moex-102-9a386a01', 'sub-real-estate-06', NULL, 'single_choice', '管仲既任政相齊，以區區之齊，在海濱，通貨積財，富國彊兵，與俗同好惡。故其 稱曰：「倉廩實而知禮節；衣食足而知榮辱。上服度，則六親固。四維不張，國乃 滅亡。下令如流水之原，令順民心。」故論卑而易行。俗之所欲，因而予之；俗之 所否，因而去之。（司馬遷《史記．管晏列傳》）文中「與俗同好惡」語義與下列 何者最為貼近？', '["好惡與聖人同", "民之所欲，常在我心", "作之君，作之親，作之師", "風俗之厚薄繫乎一二人心之所向"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:10+00:00", "source_pdf_sha1": "d22f9357c134", "answer_pdf_sha1": "5bbb7ca18052", "source_family": "moex-gov-tw", "moex": {"exam_code": "102180", "c": "601", "s": "1105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "102", "exam_name": "102年專技高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01813', 'real-estate', 'real-estate-moex-102-9a386a01', 'sub-real-estate-06', NULL, 'single_choice', '《荀子》云：「術正而心順之，則形相雖惡而心術善，無害為君子也。形相雖善而 心術惡，無害為小人也。君子之謂吉，小人之謂凶。」根據上文，下列選項何者最 為貼近？', '["相人之術是一門重要的學問", "形貌美醜影響一個人的吉凶禍福", "吉凶以人格決定，不以形相決定", "形貌是一個人成為君子的重要條件"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:10+00:00", "source_pdf_sha1": "d22f9357c134", "answer_pdf_sha1": "5bbb7ca18052", "source_family": "moex-gov-tw", "moex": {"exam_code": "102180", "c": "601", "s": "1105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "102", "exam_name": "102年專技高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01814', 'real-estate', 'real-estate-moex-102-9a386a01', 'sub-real-estate-06', NULL, 'single_choice', '生活的藝術，有一部份我不是不能領略。我懂得怎麼看『七月巧雲』，聽蘇格蘭兵 吹 bagpipe，享受微風中的籐椅，吃鹽水花生，欣賞雨夜的霓虹燈，從雙層公共汽 車上伸出手摘樹巔的綠葉。在沒有人與人交接的場合，我充滿了生命的歡悅。可是 我一天不能克服這種咬嚙性的小煩惱，生命是一襲華美的袍，爬滿了蚤子。（張愛 玲〈天才夢〉）以下敘述何者錯誤？', '["作者懂得領略部分生活中的藝術", "作者在人與人交接的場合裡，容易感到不自在", "文中「咬嚙性的小煩惱」是指獨處的孤寂", "「生命是一襲華美的袍，爬滿了蚤子。」這是運用了「象徵」的手法"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:10+00:00", "source_pdf_sha1": "d22f9357c134", "answer_pdf_sha1": "5bbb7ca18052", "source_family": "moex-gov-tw", "moex": {"exam_code": "102180", "c": "601", "s": "1105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "102", "exam_name": "102年專技高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01815', 'real-estate', 'real-estate-moex-102-9a386a01', 'sub-real-estate-06', NULL, 'single_choice', '「世路中人，或圖功名，或治生產，儘自正經。爭奈天地間好風月、好山水、好書 籍，了不相涉，豈非枉卻一生？」關於以上文字的敘述，下列選項何者最為貼近？', '["本文旨在強調能享受生活樂趣的人，也才能在圖功名、治生產時有優異的表現", "「或圖功名，或治生產，儘自正經」，意指圖功名、治生產，都要以平常心去面對", "文中所謂「枉卻一生」者，乃指熱衷於功名、生產，卻不知在風月、山水、書籍 間找到生活樂趣的人", "「爭奈天地間好風月、好山水、好書籍，了不相涉」，意指遊覽自然風月山水， 與專心讀書，是截然不同的事 60210"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:10+00:00", "source_pdf_sha1": "d22f9357c134", "answer_pdf_sha1": "5bbb7ca18052", "source_family": "moex-gov-tw", "moex": {"exam_code": "102180", "c": "601", "s": "1105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "102", "exam_name": "102年專技高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01816', 'real-estate', 'real-estate-moex-102-9a386a01', 'sub-real-estate-06', NULL, 'single_choice', '以下「」內的數字，何者為實際數目，而非虛數？', '["欲窮「千里」目，更上一層樓（王之渙〈登鸛鵲樓〉）", "「三顧」頻煩天下計，兩朝開濟老臣心（杜甫〈蜀相〉）", "相見時難別亦難，東風無力「百花」殘（李商隱〈無題〉）", "五花馬，千金裘，呼兒將出換美酒，與爾同銷「萬古」愁（李白〈將進酒〉） 那一雙傲慢的靴子至今還落在／高力士羞憤的手裡，人卻不見了／把滿地的難民和傷兵／ 把胡馬和羌笛交踐的節奏／留給杜二去細細的苦吟／自從那年賀知章眼花了／認你做 謫仙，便更加佯狂／用一隻中了魔咒的小酒壺／把自己藏起來，連太太也尋不到你／怨 長安城小而壺中天長（余光中）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:10+00:00", "source_pdf_sha1": "d22f9357c134", "answer_pdf_sha1": "5bbb7ca18052", "source_family": "moex-gov-tw", "moex": {"exam_code": "102180", "c": "601", "s": "1105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "102", "exam_name": "102年專技高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01817', 'real-estate', 'real-estate-moex-102-9a386a01', 'sub-real-estate-06', NULL, 'single_choice', '這首詩描寫的人物應是下列何人？', '["詩佛", "詩仙", "詩聖", "詩鬼"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:10+00:00", "source_pdf_sha1": "d22f9357c134", "answer_pdf_sha1": "5bbb7ca18052", "source_family": "moex-gov-tw", "moex": {"exam_code": "102180", "c": "601", "s": "1105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "102", "exam_name": "102年專技高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01818', 'real-estate', 'real-estate-moex-102-9a386a01', 'sub-real-estate-06', NULL, 'single_choice', '根據上文，詩中所描寫的人物，不包括下列那項特質？', '["佯狂", "嗜酒", "傲慢", "矯情"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:10+00:00", "source_pdf_sha1": "d22f9357c134", "answer_pdf_sha1": "5bbb7ca18052", "source_family": "moex-gov-tw", "moex": {"exam_code": "102180", "c": "601", "s": "1105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "102", "exam_name": "102年專技高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01819', 'real-estate', 'real-estate-moex-102-9a386a01', 'sub-real-estate-06', NULL, 'single_choice', '下列選項與「百萬買房，千萬買鄰」意思相差最遠的是：', '["孟母三遷，以教其子", "君子居必擇鄉，遊必就士", "里仁為美，擇不處仁，焉得知", "肯與鄰翁相對飲，隔籬呼取盡餘杯"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:10+00:00", "source_pdf_sha1": "d22f9357c134", "answer_pdf_sha1": "5bbb7ca18052", "source_family": "moex-gov-tw", "moex": {"exam_code": "102180", "c": "601", "s": "1105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "102", "exam_name": "102年專技高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01820', 'real-estate', 'real-estate-moex-102-9a386a01', 'sub-real-estate-06', NULL, 'single_choice', '《史記．淮陰侯列傳》：「（韓）信釣於城下，諸母漂，有一母見信飢，飯信，竟 漂數十日。信喜，謂漂母曰：『吾必有以重報母。』母怒曰：『大丈夫不能自食， 吾哀王孫而進食，豈望報乎？』」關於這段文字的理解與詮釋，下列何者正確？', '["「大丈夫不能自食」意為「大丈夫不能養活自己」，「食」為動詞", "「竟漂數十日」意為「竟然連續漂洗綿絮長達幾十天」，「漂」為名詞", "「吾必有以重報母」意為「我一定會對你嚴加報復」，「報」為動詞", "「吾哀王孫而進食」意為「我可憐你才給你飯吃」，「哀」為形容詞"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:10+00:00", "source_pdf_sha1": "d22f9357c134", "answer_pdf_sha1": "5bbb7ca18052", "source_family": "moex-gov-tw", "moex": {"exam_code": "102180", "c": "601", "s": "1105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "102", "exam_name": "102年專技高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01821', 'real-estate', 'real-estate-moex-102-9a386a01', 'sub-real-estate-06', NULL, 'single_choice', '下列文句「」內的詞語，屬於謙詞用法的是：', '["余小時，「大人」令誦〈子虛賦〉，私心慕之", "「足下」欲使吾適人之適，而吾欲自適其適，非敢非足下之義也", "衛使客事魏，三年不得見，衛客患之，乃見梧下「先生」，許之以百金", "「不佞」竊嘗謬議，今公私匱竭之際，惟有錢法一事，可以通利權、便民裕國"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:10+00:00", "source_pdf_sha1": "d22f9357c134", "answer_pdf_sha1": "5bbb7ca18052", "source_family": "moex-gov-tw", "moex": {"exam_code": "102180", "c": "601", "s": "1105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "102", "exam_name": "102年專技高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL)
